import org.junit.jupiter.api.Test;

class LmdbUnifiedJoinRoutingTest {

	@Test
	void productionRegistryInstallsLegacyOwnerWithoutApplyingItToPureInnerJoins() {
		List<String> ruleIds = registry().rules().stream().map(CascadesRule::id).toList();
		List<String> applicableRuleIds = applicableRuleIds(connectedJoin());

		assertAll(
				() -> assertTrue(ruleIds.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID), ruleIds::toString),
				() -> assertFalse(applicableRuleIds.contains(LmdbCascadesConnectedJoinPlanner.RULE_ID),
						applicableRuleIds::toString));
	}

	@Test
	void connectedJoinRetainsGenericImplementationAlternative() {
		List<String> applicableRuleIds = applicableRuleIds(connectedJoin());

		assertTrue(applicableRuleIds.contains("generic-physical-implementation"), applicableRuleIds::toString);
	}

	@Test
	void connectedJoinRetainsBoundLookupImplementationAlternative() {
		List<String> applicableRuleIds = applicableRuleIds(connectedJoin());

		assertTrue(applicableRuleIds.contains("lmdb-inner-join-bound-lookup"), applicableRuleIds::toString);
	}

	@Test
	void optimizerRoutesConnectedJoinThroughUnifiedSearchForBothAlgorithmSettings() {
		String previousMode = System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "exact");
		String previousPolicy = System.setProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, "off");
		String previousDphyp = System.getProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY);
		try {
			RoutingObservation dphyp = optimizeConnectedJoin(true);
			RoutingObservation exhaustive = optimizeConnectedJoin(false);

			assertAll(
					() -> assertTrue(dphyp.evidence().contains("joinRegionsSaturated=1"),
							dphyp::evidence),
					() -> assertEquals("COMPLETE", dphyp.completeness(), dphyp::evidence),
					() -> assertTrue(exhaustive.evidence().contains("joinRegionsSaturated=1"),
							exhaustive::evidence),
					() -> assertEquals("COMPLETE", exhaustive.completeness(), exhaustive::evidence));
		} finally {
			restoreProperty(LmdbCascadesOptimizer.MODE_PROPERTY, previousMode);
			restoreProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, previousPolicy);
			restoreProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, previousDphyp);
		}
	}

	private static RuleRegistry registry() {
		return LmdbCascadesRuleProvider.rules(new JoinCostStatistics());
	}

	private static List<String> applicableRuleIds(TupleExpr tupleExpr) {
		RuleRegistry registry = registry();
		Memo memo = new Memo(CascadesCostModel.from(new JoinCostStatistics()));
		int groupId = memo.intern(tupleExpr);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		return registry.applicableRules(expression, OptimizationGoal.root(), memo)
				.stream()
				.map(CascadesRule::id)
				.toList();
	}

	private static TupleExpr connectedJoin() {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		return new Join(
				new StatementPattern(new Var("subject"),
						Var.of("leftPredicate", values.createIRI("urn:left"), false, true),
						new Var("shared")),
				new StatementPattern(new Var("shared"),
						Var.of("rightPredicate", values.createIRI("urn:right"), false, true),
						new Var("object")));
	}

	private static RoutingObservation optimizeConnectedJoin(boolean dphypEnabled) {
		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, Boolean.toString(dphypEnabled));
		QueryRoot root = new QueryRoot(connectedJoin());
		new LmdbCascadesOptimizer(new JoinCostStatistics(), false).optimize(root, null,
				EmptyBindingSet.getInstance());
		return new RoutingObservation(root.getStringMetricPlanned("optimizer.cascadesCompleteness"),
				routingEvidence(root));
	}

	private static String routingEvidence(TupleExpr tupleExpr) {
		List<String> evidence = new ArrayList<>();
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				addMetric(evidence, node, "optimizer.cascadesProofs");
				addMetric(evidence, node, "optimizer.cascadesDiagnostics");
				super.meetNode(node);
			}
		});
		return String.join(" | ", evidence);
	}

	private static void addMetric(List<String> evidence, QueryModelNode node, String name) {
		String value = node.getStringMetricPlanned(name);
		if (value != null && !value.isBlank()) {
			evidence.add(name + '=' + value);
		}
	}

	private static void restoreProperty(String name, String previousValue) {
		if (previousValue == null) {
			System.clearProperty(name);
		} else {
			System.setProperty(name, previousValue);
		}
	}

	private record RoutingObservation(String completeness, String evidence) {
	}

	private static final class JoinCostStatistics extends EvaluationStatistics implements JoinFactorCostModel {
		@Override
		public double getCardinality(TupleExpr expr) {
			return 10.0d;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			return Optional.of(new FactorCostEstimate(10.0d, 10.0d));
		}
	}
}
